import React, { useEffect, useState } from "react";
import axios from "axios";

const API_URL = "http://localhost:7000/api/prices";
const CATEGORY_URL = "http://localhost:7000/api/categories";

export default function PriceList() {
  const [items, setItems] = useState([]);
  const [categories, setCategories] = useState([]);
  const [form, setForm] = useState({
    name: "",
    category: "",
    description: "",
    basePrice: "",
    difference: "",
    validTill: "",
    imageFile: null,
  });
  const [editId, setEditId] = useState(null);

  useEffect(() => {
    fetchItems();
    fetchCategories();
  }, []);

  const fetchItems = async () => {
    const res = await axios.get(API_URL);
    setItems(res.data);
  };

  const fetchCategories = async () => {
    const res = await axios.get(CATEGORY_URL);
    setCategories(res.data.categories || []);
  };

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (name === "file") setForm({ ...form, imageFile: files[0] });
    else setForm({ ...form, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    Object.keys(form).forEach((key) => {
      if (form[key]) formData.append(key, form[key]);
    });

    if (editId)
      await axios.put(`${API_URL}/${editId}`, formData);
    else
      await axios.post(API_URL, formData);

    setForm({
      name: "",
      category: "",
      description: "",
      basePrice: "",
      difference: "",
      validTill: "",
      imageFile: null,
    });
    setEditId(null);
    fetchItems();
  };

  const handleEdit = (item) => {
    setForm({
      name: item.name,
      category: item.category._id,
      description: item.description || "",
      basePrice: item.basePrice,
      difference: item.difference,
      validTill: item.validTill?.split("T")[0] || "",
      imageFile: null,
    });
    setEditId(item._id);
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4 text-center">💰 Price Manager</h2>

      <form onSubmit={handleSubmit} className="bg-gray-100 p-4 rounded mb-6 shadow-md">
        <input
          name="name"
          placeholder="Item Name"
          value={form.name}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />

        {/* CATEGORY DROPDOWN */}
        <select
          name="category"
          value={form.category}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        >
          <option value="">Select Category</option>
          {categories.map((cat) => (
            <option key={cat._id} value={cat._id}>{cat.name}</option>
          ))}
        </select>

        {/* DESCRIPTION */}
        <textarea
          name="description"
          placeholder="Description"
          value={form.description}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />

        <input
          type="number"
          name="basePrice"
          placeholder="Base Price"
          value={form.basePrice}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />
        <input
          type="number"
          name="difference"
          placeholder="Price Difference"
          value={form.difference}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />
        <input
          type="date"
          name="validTill"
          value={form.validTill}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />
        <input
          type="file"
          name="file"
          onChange={handleChange}
          className="border p-2 mb-3 w-full"
        />

        <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded">
          {editId ? "Update" : "Add"}
        </button>
      </form>

      {/* TABLE SAME AS BEFORE */}
      {/* (Keep your table code unchanged) */}
    </div>
  );
}
